local xml = require("LuaXML")

local function read_request_body()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    
    if not body then
        local body_file = ngx.req.get_body_file()
        if body_file then
            local file = io.open(body_file, "r")
            if file then
                body = file:read("*all")
                file:close()
            end
        end
    end
    
    return body
end

local function get_element_text(element)
    if type(element) == "table" then
        for _, child in ipairs(element) do
            if type(child) == "string" then
                return child
            end
        end
    end
    return ""
end

local function find_element(root, tag_name)
    if not root or type(root) ~= "table" then
        return nil
    end
    
    if root[0] == tag_name then
        return root
    end
    
    for _, child in ipairs(root) do
        if type(child) == "table" then
            local found = find_element(child, tag_name)
            if found then
                return found
            end
        end
    end
    
    return nil
end

local function find_elements(root, tag_name, results)
    results = results or {}
    
    if not root or type(root) ~= "table" then
        return results
    end
    
    if root[0] == tag_name then
        table.insert(results, root)
    end
    
    for _, child in ipairs(root) do
        if type(child) == "table" then
            find_elements(child, tag_name, results)
        end
    end
    
    return results
end

local function get_attribute(element, attr_name)
    if type(element) == "table" then
        return element[attr_name]
    end
    return nil
end

local function parse_soap_envelope(xml_root)
    local envelope = find_element(xml_root, "Envelope") or 
                     find_element(xml_root, "soap:Envelope") or
                     find_element(xml_root, "soapenv:Envelope")
    
    if not envelope then
        return nil, "SOAP Envelope not found"
    end
    
    local body = find_element(envelope, "Body") or 
                 find_element(envelope, "soap:Body") or
                 find_element(envelope, "soapenv:Body")
    
    if not body then
        return nil, "SOAP Body not found"
    end
    
    local header = find_element(envelope, "Header") or 
                   find_element(envelope, "soap:Header") or
                   find_element(envelope, "soapenv:Header")
    
    return {
        envelope = envelope,
        header = header,
        body = body
    }
end

local function extract_soap_action(soap_structure)
    if not soap_structure or not soap_structure.body then
        return nil
    end
    
    for _, child in ipairs(soap_structure.body) do
        if type(child) == "table" and child[0] then
            return child[0], child
        end
    end
    
    return nil
end

local function xml_to_table(element)
    if type(element) ~= "table" then
        return element
    end
    
    local result = {
        _tag = element[0]
    }
    
    for k, v in pairs(element) do
        if type(k) == "string" and k ~= "0" then
            result[k] = v
        end
    end
    
    for i, child in ipairs(element) do
        if type(child) == "string" then
            result._text = (result._text or "") .. child
        elseif type(child) == "table" then
            local tag = child[0]
            local converted = xml_to_table(child)
            
            if result[tag] then
                if type(result[tag]) ~= "table" or result[tag]._tag then
                    result[tag] = {result[tag]}
                end
                table.insert(result[tag], converted)
            else
                result[tag] = converted
            end
        end
    end
    
    return result
end

local function create_soap_response(action, data)
    local response = '<?xml version="1.0" encoding="UTF-8"?>'
    response = response .. '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">'
    response = response .. '<soap:Body>'
    response = response .. '<' .. action .. 'Response>'
    
    if type(data) == "table" then
        for k, v in pairs(data) do
            response = response .. '<' .. k .. '>' .. tostring(v) .. '</' .. k .. '>'
        end
    else
        response = response .. tostring(data)
    end
    
    response = response .. '</' .. action .. 'Response>'
    response = response .. '</soap:Body>'
    response = response .. '</soap:Envelope>'
    
    return response
end

local function create_soap_fault(faultcode, faultstring)
    local fault = '<?xml version="1.0" encoding="UTF-8"?>'
    fault = fault .. '<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">'
    fault = fault .. '<soap:Body>'
    fault = fault .. '<soap:Fault>'
    fault = fault .. '<faultcode>' .. faultcode .. '</faultcode>'
    fault = fault .. '<faultstring>' .. faultstring .. '</faultstring>'
    fault = fault .. '</soap:Fault>'
    fault = fault .. '</soap:Body>'
    fault = fault .. '</soap:Envelope>'
    
    return fault
end

local function process_request()
    local xml_body = read_request_body()
    
    if not xml_body or xml_body == "" then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(create_soap_fault("soap:Client", "Empty request body"))
        return ngx.exit(400)
    end
    
    local ok, xml_root = pcall(xml.eval, xml_body)
    
    if not ok or not xml_root then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(create_soap_fault("soap:Client", "Invalid XML format"))
        return ngx.exit(400)
    end
    
    local soap_structure, err = parse_soap_envelope(xml_root)
    
    if not soap_structure then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(create_soap_fault("soap:Client", err or "Invalid SOAP structure"))
        return ngx.exit(400)
    end
    
    local action_name, action_element = extract_soap_action(soap_structure)
    
    if not action_name then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(create_soap_fault("soap:Client", "No action found in SOAP body"))
        return ngx.exit(400)
    end
    
    local action_data = xml_to_table(action_element)
    
    ngx.ctx.soap_action = action_name
    ngx.ctx.soap_data = action_data
    ngx.ctx.soap_structure = soap_structure
    ngx.ctx.xml_root = xml_root
    
    return true
end

